import React from "react"
import { properties } from '../../properties/properties.js'
import Select from 'react-select'

class CyberAdmin extends React.Component {

    constructor(props) {
        super(props);
        this.state = { screen: 1, result: [], ho: [], team: []
        };
    }


    createAlgorithmAPI = () => {

    }


    onChangeAssignHO = (selectedOptions) => {
        this.setState({ho: selectedOptions})
        console.log(selectedOptions)
    }

    onChangeTeam = (selectedOptions) => {
        this.setState({team: selectedOptions})
        console.log(selectedOptions)
    }


    createNewAlgorithm = (evt) => {


        this.setState({screen: 2})

    }

    cancelCreate = (evt) => {
        this.setState({screen: 1})
    }


    componentDidMount() {

        this.setState({screen: 0});

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');


        var backUrl = properties.backend + `cyberraptor/algorithms`

        fetch(backUrl, {
          "method": "GET",
          headers: headers
        })
        .then(response => response.json())
        .then(response => {
            this.setState({result: response})
            this.setState({screen: 1})
        })
        .catch(err => {
          console.log(err);
        });

    }


    render() {


        var header = "Loading ..."
        var content = []
        var borderStyleString = "1px solid black"
        var divStyleString = {marginTop: "10px"}
        var marginTop = "10px"
        var redColor = {color: "red"}
        var divStyleDoubleString = {marginTop: "20px"}


        if (this.state.screen == 2) {
            header = ""




            content.push(<div style={divStyleString}><span style={{fontSize: '20px'}}>Create New Algorithm</span></div>)

            content.push(<div style={{divStyleString}}>&nbsp;</div>)


            content.push(<div style={{divStyleString}}><span style={redColor}>* is require</span></div>)


            content.push(<div style={divStyleString}><span style={redColor}>*</span> How many/position HO assign on this step?</div>)


            var options = [
                {label: '1st HO', value: '1stHO'},
                {label: '2nd HO', value: '2ndHO'},
                {label: '3rd HO', value: '3rdHO'},
                {label: '4th HO', value: '4thHO'},
                {label: '1 HO', value: 'upto1'},
                {label: 'Up to 2 HO', value: 'upto2'},
                {label: 'Up to 3 HO', value: 'upto3'},
                {label: 'Up to 4 HO', value: 'upto4'}
              ]


            content.push(<div style={{marginTop: marginTop, width: "300px"}}><Select isMulti={false} id="upTo" onChange={this.onChangeAssignHO} options={options} className="basic-multi-select"
            classNamePrefix="select"></Select> </div>)

            content.push(<div style={divStyleString}><span style={redColor}>*</span> Which team?</div>)


            options = [
                {label: 'call', value: 'call'},
                {label: 'GMS', value: 'GMS'},
                {label: 'postpost', value: 'postpost'}
              ]


            content.push(<div style={{marginTop: marginTop, width: "300px"}}><Select isMulti={false} id="upTo" onChange={this.onChangeTeam} options={options} className="basic-multi-select"
            classNamePrefix="select"></Select></div>)


            content.push(<div style={divStyleString}><hr></hr></div>)

            options = [
                {label: 'equal', value: 'equal'},
                {label: 'fewer', value: 'fewer'}
              ]

              const selectStyles = {
                valueContainer: () => ({
                    padding: 10,
                    display: "flex",
                    alignItems: "center"
                }),
                menu: () => ({
                    zIndex: 50,
                    position: "fixed",
                    backgroundColor: "#fff"
                }),
            }



            content.push(<div style={{marginTop: "20px", overflow: "hidden"}}><div style={{float: "left"}}>Starting census of &nbsp;
            <input style={{width: "50px", height: "35px", border: "solid 1px lightgrey"}} id="startcensus"></input>&nbsp;or&nbsp;</div>
            <div style={{float: "left", height: "130px"}}><Select isMulti={false} id="startingCensusSelect" onChange={this.onChangeStartingCensus} options={options} 
           style={selectStyles}></Select></div></div>)

            content.push(<div style={divStyleDoubleString}>Up to census of &nbsp;<input style={{width: "50px", height: "35px", border: "solid 1px lightgrey"}} id="upcensus"></input></div>)


            options = []
            options.push(<option key="" value=""></option>)
            options.push(<option key="1" value="1">1</option>)
            options.push(<option key="2" value="2">2</option>)
            options.push(<option key="3" value="3">3</option>)
            options.push(<option key="4" value="4">4</option>)
            content.push(<div style={divStyleDoubleString}>Max <select id="maxho">{options}</select> HO</div>)

            options = []
            options.push(<option key="" value=""></option>)
            options.push(<option key="yes" value="yes">Yes</option>)
            options.push(<option key="no" value="no">No</option>)
            content.push(<div style={divStyleDoubleString}>resintern: <select id="resintern">{options}</select>&nbsp;&nbsp;full team: <select id="fullteam">{options}</select> </div>)



            content.push(<div style={divStyleDoubleString}><button onClick={this.createNewAlgorithm} >create algorithm</button>&nbsp;<button onClick={this.cancelCreate} >Cancel</button></div>)

        }


        if (this.state.screen == 1) {


            header = ""


            var tableContent = []
            tableContent.push(<tr><td style={{border:  borderStyleString, fontSize: '20px', padding: '5px'}} colSpan="3">Available algorithms to create steps</td></tr>)


            for (var index in this.state.result) {

                var singleResult = this.state.result[index]
                var translateString = ""

                //********************************************************************** */
                var resFull = ""
                if (singleResult.resintern) {
                    resFull = " if resintern day"
                }
                if (singleResult.resintern != null && !singleResult.resintern) {
                    resFull = " (non-resintern)"
                }
                if (singleResult.fullteam) {
                    resFull = " if full team present"
                }

                var teamString = "each " + singleResult.type + " team" + resFull

                //********************************************************************** */
                var maxCensus = ""
                if (singleResult.max_census) {
                    maxCensus = ", up to census of " + singleResult.max_census
                }

                //********************************************************************** */
                var maxHO = ""
                if (singleResult.max_ho) {
                    maxHO = " (max* " + singleResult.max_ho + " HO)"
                }


                if (singleResult.current_ho || singleResult.current_ho == 0) {
                    var num 
                    if (singleResult.current_ho + 1 === 1) 
                        num = "st"
                    if (singleResult.current_ho + 1 === 2) 
                        num = "nd"
                    if (singleResult.current_ho + 1 == 3) 
                        num = "rd"
                    if (singleResult.current_ho + 1 > 3) 
                        num = "th"

                    translateString += (singleResult.current_ho + 1) + num + " HO to " + teamString

                    if (singleResult.census) {
                        if (singleResult.census < 0) {
                            translateString += " with starting census of " + singleResult.census * -1 + " or fewer"
                        } else {
                            translateString += " with starting census of " + singleResult.census
                        }
                    }

                    translateString += maxCensus + maxHO

                } else {
                    if (singleResult.ho > 1)
                        translateString = "Up to " + singleResult.ho + " HO to " + teamString
                    else 
                        translateString = singleResult.ho + " HO to " + teamString

                    translateString += maxCensus + maxHO


                }








                tableContent.push(<tr><td style={{border:  borderStyleString, padding: '10px'}}>{translateString}</td><td style={{border:  borderStyleString, padding: '10px'}}><button style={{marginLeft: '12px'}} onClick={this.createNewAlgorithm} >Add to step</button></td><td style={{border:  borderStyleString, padding: '10px'}}><button style={{marginLeft: '12px'}} onClick={this.createNewAlgorithm} >Replace</button></td></tr>)
            }

            content.push(<div style={{marginBottom: "10px"}}><button style={{marginLeft: '12px'}} onClick={this.createNewAlgorithm} >Create New Algorithm</button></div>)

            content.push(<table style={{border: borderStyleString}}>{tableContent}</table>)



        }


        return (
            <div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}
            </div>
        );


      }


}


export default CyberAdmin
